  const PROPAGATOR_VERSION = (this.PROPAGATOR_VERSION !== null ? builder.createString(this.PROPAGATOR_VERSION!) : 0);
  const AEROTHERMAL_MODEL = (this.AEROTHERMAL_MODEL !== null ? builder.createString(this.AEROTHERMAL_MODEL!) : 0);
  const BREAKUP_MODEL = (this.BREAKUP_MODEL !== null ? builder.createString(this.BREAKUP_MODEL!) : 0);
