  REM.startREM(builder);
  REM.addMessageId(builder, MESSAGE_ID);
  REM.addCreationDate(builder, CREATION_DATE);
  REM.addOriginator(builder, ORIGINATOR);
  REM.addObjectName(builder, OBJECT_NAME);
  REM.addObjectId(builder, OBJECT_ID);
  REM.addNoradCatId(builder, this.NORAD_CAT_ID);
  REM.addTimeSystem(builder, TIME_SYSTEM);
  REM.addRefFrame(builder, REF_FRAME);
  REM.addStartTime(builder, START_TIME);
  REM.addStopTime(builder, STOP_TIME);
  REM.addStepSize(builder, this.STEP_SIZE);
  REM.addReentryData(builder, REENTRY_DATA);
  REM.addTrajectoryOem(builder, TRAJECTORY_OEM);
  REM.addTrajectoryOcm(builder, TRAJECTORY_OCM);
  REM.addAtmosphere(builder, ATMOSPHERE);
  REM.addHypersonicConditions(builder, HYPERSONIC_CONDITIONS);
  REM.addPropagatorName(builder, PROPAGATOR_NAME);
  REM.addPropagatorVersion(builder, PROPAGATOR_VERSION);
  REM.addAerothermalModel(builder, AEROTHERMAL_MODEL);
  REM.addBreakupModel(builder, BREAKUP_MODEL);
  REM.addOutcome(builder, this.OUTCOME);
  REM.addBreakupMode(builder, this.BREAKUP_MODE);
  REM.addEntryInterfaceEpoch(builder, ENTRY_INTERFACE_EPOCH);
  REM.addEntryInterfaceAltitudeM(builder, this.ENTRY_INTERFACE_ALTITUDE_M);
  REM.addPeakHeatingEpoch(builder, PEAK_HEATING_EPOCH);
